module RefModule(
  input clk,
  input reset,
  input [99:0] in,
  output reg [99:0] out
);reg [99:0] temp;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
  if (reset) begin
    temp <= 0;
    out <= 0;
  end else begin
    temp <= in;
    out <= temp;
  end
end

endmodule
